function esc(value){return String(value==null?'':value).replace(/[&<>"']/g,function(ch){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]})}
function csv(value){return String(value||'').split(/[\n,]/).map(function(item){return item.trim()}).filter(Boolean)}
function fmt(value){return value?new Date(value).toLocaleString('ko-KR',{month:'numeric',day:'numeric',hour:'2-digit',minute:'2-digit'}):'-'}
function evidenceLabel(value){var labels={verified:'근거 확인',topic_unverified:'주제 근거 미확인',target_unverified:'대상 근거 미확인',stance_unverified:'어조 근거 미확인',topic_and_target_unverified:'주제·대상 근거 미확인',topic_and_stance_unverified:'주제·어조 근거 미확인',target_and_stance_unverified:'대상·어조 근거 미확인',topic_and_target_and_stance_unverified:'주제·대상·어조 근거 미확인',body_limited_verified:'본문 제한 · 근거 확인',body_limited_topic_unverified:'본문 제한 · 주제 근거 미확인',body_limited_target_unverified:'본문 제한 · 대상 근거 미확인',body_limited_stance_unverified:'본문 제한 · 어조 근거 미확인',body_limited_topic_and_target_unverified:'본문 제한 · 주제·대상 근거 미확인',body_limited_topic_and_stance_unverified:'본문 제한 · 주제·어조 근거 미확인',body_limited_target_and_stance_unverified:'본문 제한 · 대상·어조 근거 미확인',body_limited_topic_and_target_and_stance_unverified:'본문 제한 · 주제·대상·어조 근거 미확인'};return labels[value]||''}
function userReason(value){var text=String(value||'').trim();if(!text)return'';var labels={publisher_filtered:'허용된 언론사가 아니라 후보에서 제외했습니다.',exclude_terms_matched:'제외 키워드가 포함되어 후보에서 제외했습니다.',required_terms_missing:'필수 키워드가 확인되지 않아 후보에서 제외했습니다.',include_terms_missing:'포함 키워드가 확인되지 않아 후보에서 제외했습니다.',negative_signal_missing:'부정 이슈를 찾는 케이스지만 기사에서 부정 신호가 확인되지 않았습니다.',semantic_below_threshold:'케이스 주제와 의미 유사도가 낮아 후보에서 제외했습니다.',required_topic_not_verified:'케이스의 필수 주제를 뒷받침하는 기사 근거가 부족합니다.',topic_target_not_verified:'기사에서 대상 기관·인물이 핵심 주체로 확인되지 않았습니다.',topic_stance_not_verified:'케이스가 요구한 어조가 기사에서 확인되지 않았습니다.',operational_factual_report:'재난·대응 사실 전달 기사라 직접 비판 근거가 부족합니다.',excluded_term:'제외 키워드가 포함되어 발송에서 제외했습니다.',low_semantic_similarity:'케이스 주제와 기사 내용의 의미 유사도가 낮습니다.',llm_topic_mismatch:'케이스 주제와 기사 핵심 내용이 다릅니다.',llm_simple_mention:'관련 표현이 단순히 언급된 수준입니다.',llm_insufficient_relevance:'케이스 조건을 충족할 만큼 관련성이 높지 않습니다.',llm_different_context:'비슷한 표현은 있지만 다른 맥락의 기사입니다.',llm_body_insufficient:'본문 근거가 부족해 관련성을 확인하지 못했습니다.',body_unavailable:'기사 본문을 충분히 확인하지 못했습니다.',llm_unavailable:'판정 모델 응답을 확보하지 못했습니다.',case_llm_unavailable:'케이스 판정 모델 응답을 확보하지 못했습니다.',topic_not_configured:'케이스 주제 설정이 비어 있습니다.',required_term_missing:'필수 키워드가 확인되지 않았습니다.'};if(labels[text])return labels[text];if(/^[a-z0-9_]+$/.test(text))return'세부 조건을 충족하지 못했습니다.';return text}
function userReasons(values){var result=[];(values||[]).forEach(function(value){var reason=userReason(value);if(reason&&result.indexOf(reason)<0)result.push(reason)});return result}
function toast(message){var dialog=$('analysisDialog');var el=dialog&&dialog.open?$('analysisToast'):$('toast');el.textContent=message;el.classList.add('show');clearTimeout(toast.timer);toast.timer=setTimeout(function(){el.classList.remove('show')},3500)}
async function req(path,options){options=options||{};var response=await fetch(path,Object.assign({cache:'no-store',credentials:'same-origin'},options,{headers:Object.assign({'Content-Type':'application/json'},options.headers||{})}));var data={};try{data=await response.json()}catch(e){}if(!response.ok){var error=new Error(data.error||'요청 실패 ('+response.status+')');error.status=response.status;throw error}return data}

function showView(name,focusId){$('manualView').hidden=name!=='manual';$('signupView').hidden=name!=='signup';$('dashboardView').hidden=name!=='dashboard';$('neuralView').hidden=name!=='neural';$('pressView').hidden=name!=='press';$('adminView').hidden=name!=='admin';document.querySelectorAll('.nav').forEach(function(button){button.classList.toggle('active',button.dataset.view===name)});if(name==='manual')return;else if(name==='admin')loadAdmin();else if(name==='neural')loadNeural();else if(name==='press')loadPress(focusId);else if(name==='signup')loadSignup();else loadDashboard(state.activeCase,state.activeOrganization)}
document.querySelectorAll('.nav[data-view]').forEach(function(button){button.onclick=function(){showView(button.dataset.view)}});

function signupStatusLabel(value){return {requested:'구독 요청',kakao_registered:'카카오 구독등록완료',approved:'구독 승인',partial:'일부 승인',rejected:'반려',revoked:'구독 해지'}[value]||value||'구독 요청'}
function signupCaseStatusLabel(value){return {pending:'검토 대기',approved:'수신중',rejected:'반려',revoked:'해지'}[value]||value||'검토 대기'}
function signupKakaoWarning(){return '반드시 카카오 로그인 후, [선택] 카카오 메시지 전송을 선택하셔야지 실제 메시지가 발송됩니다.'}
function updateSignupSelectAll(){var all=$('signupSelectAll'),list=$('signupCaseList');if(!all||!list)return;var inputs=Array.from(list.querySelectorAll('input[type="checkbox"]')),enabled=!!state.signupKakaoRegistered&&inputs.length>0;var checked=inputs.filter(function(input){return input.checked}).length;all.disabled=!enabled;all.checked=enabled&&checked===inputs.length;all.indeterminate=enabled&&checked>0&&checked<inputs.length}
function updateSignupGate(){var ok=!!state.signupKakaoRegistered;$('signupName').disabled=!ok;$('signupOrganization').disabled=!ok;$('signupCaseFieldset').disabled=!ok;$('submitSignupRequest').disabled=!ok;$('startKakaoSignup').disabled=ok;$('startKakaoSignup').textContent=ok?'카카오 메시지 동의 완료':'카카오 로그인/메시지 전송 동의하기';$('signupKakaoStatus').textContent=ok?'카카오 메시지 전송 동의가 확인되었습니다. 이제 이름, 기관, 구독 대상을 선택해 주세요.':'카카오 메시지 동의 확인 전입니다. 먼저 1단계를 완료해 주세요.';$('signupKakaoStatus').classList.toggle('ready',ok);Array.from($('signupCaseList').querySelectorAll('input')).forEach(function(input){input.disabled=!ok});updateSignupSelectAll()}
function floatingTooltip(){var el=document.getElementById("floatingTooltip");if(!el){el=document.createElement("div");el.id="floatingTooltip";el.className="floating-tooltip";document.body.appendChild(el)}return el}
function positionFloatingTooltip(target){var el=floatingTooltip(),box=target.getBoundingClientRect(),margin=12,width=Math.min(430,window.innerWidth-margin*2);el.style.maxWidth=width+"px";var rect=el.getBoundingClientRect(),left=Math.max(margin,Math.min(window.innerWidth-rect.width-margin,box.left+box.width/2-rect.width/2)),top=box.top-rect.height-10;if(top<margin)top=Math.min(window.innerHeight-rect.height-margin,box.bottom+10);el.style.left=left+"px";el.style.top=Math.max(margin,top)+"px"}
function showFloatingTooltip(target){var text=target&&target.dataset&&target.dataset.tooltip;if(!text)return;var el=floatingTooltip();el.textContent=text;el.classList.add("show");positionFloatingTooltip(target)}
function hideFloatingTooltip(){var el=document.getElementById("floatingTooltip");if(el)el.classList.remove("show")}
function bindSignupCaseTooltips(root){(root||document).querySelectorAll(".signup-case-help[data-tooltip]").forEach(function(help){help.onmouseenter=function(){showFloatingTooltip(help)};help.onmousemove=function(){positionFloatingTooltip(help)};help.onfocus=function(){showFloatingTooltip(help)};help.onmouseleave=hideFloatingTooltip;help.onblur=hideFloatingTooltip;help.onclick=function(event){event.preventDefault();event.stopPropagation();showFloatingTooltip(help)}})}
function signupTooltipTarget(event){return event.target&&event.target.closest?event.target.closest(".signup-case-help[data-tooltip]"):null}
document.addEventListener("mouseover",function(event){var target=signupTooltipTarget(event);if(target)showFloatingTooltip(target)});
document.addEventListener("mousemove",function(event){var target=signupTooltipTarget(event);if(target)positionFloatingTooltip(target)});
document.addEventListener("mouseout",function(event){var target=signupTooltipTarget(event);if(target&&!target.contains(event.relatedTarget))hideFloatingTooltip()});
document.addEventListener("focusin",function(event){var target=signupTooltipTarget(event);if(target)showFloatingTooltip(target)});
document.addEventListener("focusout",function(event){var target=signupTooltipTarget(event);if(target)hideFloatingTooltip()});
document.addEventListener("click",function(event){var target=signupTooltipTarget(event);if(target){event.preventDefault();event.stopPropagation();showFloatingTooltip(target)}});
function signupCaseTooltip(item){var prompt=String(item.topic_search_prompt||'설정된 프롬프트가 없습니다.').trim(),vector=Number(item.semantic_weight!=null?item.semantic_weight:.25),llm=Number(item.llm_weight!=null?item.llm_weight:.75),total=vector+llm,vectorPct=total?Math.round(vector/total*100):0,llmPct=total?Math.round(llm/total*100):0;return '케이스 프롬프트\n'+prompt+'\n\n분석 비율: Vector '+vectorPct+'% · LLM '+llmPct+'%\n구독자 수: '+Number(item.subscriber_count||0).toLocaleString()+'명'}
function renderSignupCases(){var org=state.signupOrganizations.find(function(item){return item.id===state.signupOrganization}),root=$('signupCaseList');if(!root)return;if(!org){root.innerHTML='<div class="empty compact">부처를 선택하세요.</div>';updateSignupGate();return}var disabled=state.signupKakaoRegistered?'':' disabled';var cases=org.cases||[];root.innerHTML=cases.length?cases.map(function(item){return '<label class="signup-case-option"><input type="checkbox" value="'+esc(item.id)+'"'+disabled+'><span class="signup-case-help" tabindex="0" data-tooltip="'+esc(signupCaseTooltip(item))+'" aria-label="케이스 설정 정보">?</span><span class="signup-case-text"><b class="signup-case-name">'+esc(item.name)+'</b></span></label>'}).join(''):'<div class="empty compact">현재 활성화된 케이스가 없습니다.</div>';root.querySelectorAll('input[type="checkbox"]').forEach(function(input){input.onchange=updateSignupSelectAll});bindSignupCaseTooltips(root);updateSignupGate()}
function renderSignupRequests(items){var root=$('signupRequestList');if(!root)return;root.innerHTML=(items||[]).length?items.map(function(item){var cases=(item.case_requests||[]).map(function(caseItem){return '<span class="signup-case-status '+esc(caseItem.status)+'">'+esc(caseItem.case_name)+' · '+esc(signupCaseStatusLabel(caseItem.status))+'</span>'}).join('');return '<article class="signup-request-row"><div><b>'+esc(item.masked_name)+'</b><small>'+esc(item.organization_name||'부처 미확인')+' · '+fmt(item.created_at)+'</small><div class="signup-case-statuses">'+cases+'</div></div><strong class="signup-status '+esc(item.status)+'">'+esc(signupStatusLabel(item.status))+'</strong></article>'}).join(''):'<div class="empty">아직 구독 요청이 없습니다.</div>'}
function proposalTermsText(values){return (values||[]).join(', ')}
function resetCaseProposalForm(){if(!$('caseProposalForm'))return;$('caseProposalId').value='';$('caseProposalTitle').value='';$('caseProposalPrompt').value='';$('caseProposalInclude').value='';$('caseProposalRequired').value='';$('caseProposalPassword').value='';$('saveCaseProposal').textContent='케이스 신청 등록'}
function proposalSource(item){return {name:item.original_title||item.title||'',topic_search_prompt:item.original_prompt||item.prompt||'',include_terms:item.original_include_terms||item.include_terms||[],required_terms:item.original_required_terms||item.required_terms||[],exclude_terms:[],urgent_terms:[],semantic_weight:.25,llm_weight:.75,keyword_weight:0,relevance_threshold:70,hold_threshold:55,send_relevant_immediately:true,delivery_mode:'immediate',collection_mode:'interval',collection_interval_minutes:30,rss_urls:[]}}
function renderCaseProposals(items){var root=$('caseProposalList');if(!root)return;items=items||[];root.innerHTML=items.length?items.map(function(item){var locked=item.content_locked&&!state.isAdmin,flagged=item.moderation_flagged&&!item.moderation_exempt,status=locked?'블라인드':(item.moderation_status==='pending'?'검사 대기':(item.moderation_status==='allowed'?'관리자 허용':'게시중'));var body=locked?'<div class="case-proposal-locked">클린 AI에 의해서 블라인드 처리되었습니다.</div>':'<div class="case-proposal-body"><p>'+esc(item.prompt||item.original_prompt||'')+'</p><small>키워드: '+esc(proposalTermsText(item.include_terms||item.original_include_terms||[]))+'</small><small>필수키워드: '+esc(proposalTermsText(item.required_terms||item.original_required_terms||[]))+'</small>'+(state.isAdmin&&item.moderation_reason?'<small>클린 AI: '+esc(item.moderation_reason)+'</small>':'')+'</div>';var actions='<div class="row-actions case-proposal-actions"><button data-edit-proposal="'+esc(item.id)+'">수정</button><button data-delete-proposal="'+esc(item.id)+'">삭제</button>'+(state.isAdmin?'<button data-register-proposal="'+esc(item.id)+'">케이스 등록</button>':'')+(state.isAdmin&&flagged?'<button data-allow-proposal="'+esc(item.id)+'">게시 허용</button>':'')+'</div>';return '<details class="case-proposal-row '+(locked?'locked':'')+'"><summary><b>'+esc(item.title)+'</b><small>'+esc(item.nickname||'익명')+' · '+esc(status)+'</small></summary>'+body+actions+'</details>'}).join(''):'<div class="empty compact">등록된 케이스 신청 글이 없습니다.</div>';bindCaseProposalRows()}
function bindCaseProposalRows(){document.querySelectorAll('[data-edit-proposal]').forEach(function(button){button.onclick=function(){var item=state.signupCaseProposals.find(function(row){return row.id===button.dataset.editProposal});if(!item){toast('신청 글을 찾지 못했습니다.');return}$('caseProposalId').value=item.id;$('caseProposalNickname').value=item.nickname||'';$('caseProposalTitle').value=item.original_title||item.title||'';$('caseProposalPrompt').value=item.original_prompt||item.prompt||'';$('caseProposalInclude').value=proposalTermsText(item.original_include_terms||item.include_terms||[]);$('caseProposalRequired').value=proposalTermsText(item.original_required_terms||item.required_terms||[]);$('caseProposalPassword').value='';$('saveCaseProposal').textContent='케이스 신청 수정';$('caseProposalTitle').focus()}});document.querySelectorAll('[data-delete-proposal]').forEach(function(button){button.onclick=async function(){var password=state.isAdmin?'':prompt('삭제하려면 등록 시 입력한 암호를 입력하세요.');if(!state.isAdmin&&!password)return;if(!confirm('이 케이스 신청 글을 삭제할까요?'))return;try{var data=await req('/api/poc/master-press/case-proposals/'+encodeURIComponent(button.dataset.deleteProposal),{method:'DELETE',body:JSON.stringify({password:password})});state.signupCaseProposals=data.items||[];renderCaseProposals(state.signupCaseProposals);toast('케이스 신청 글을 삭제했습니다.')}catch(error){toast(error.message)}}});document.querySelectorAll('[data-allow-proposal]').forEach(function(button){button.onclick=async function(){try{var data=await req('/api/poc/master-press/admin/case-proposals/'+encodeURIComponent(button.dataset.allowProposal)+'/allow',{method:'POST',body:'{}'});state.signupCaseProposals=data.items||[];renderCaseProposals(state.signupCaseProposals);toast('게시를 허용했습니다.')}catch(error){toast(error.message)}}});document.querySelectorAll('[data-register-proposal]').forEach(function(button){button.onclick=function(){var item=state.signupCaseProposals.find(function(row){return row.id===button.dataset.registerProposal});if(!item)return;state.pendingCaseProposalDraft=proposalSource(item);showView('admin')}})}
async function refreshAdminSessionSilent(){try{await req('/api/admin/session');state.isAdmin=true}catch(error){if(error.status===401)state.isAdmin=false}}
function renderSignup(data){state.signupOrganizations=data.organizations||[];state.signupRequests=data.requests||[];state.signupCaseProposals=data.case_proposals||state.signupCaseProposals||[];if(state.signupOrganization&&!state.signupOrganizations.some(function(item){return item.id===state.signupOrganization}))state.signupOrganization='';$('signupOrganization').innerHTML='<option value="">부처 선택</option>'+state.signupOrganizations.map(function(item){return '<option value="'+esc(item.id)+'">'+esc(item.name)+'</option>'}).join('');$('signupOrganization').value=state.signupOrganization;renderSignupCases();renderSignupRequests(state.signupRequests);renderCaseProposals(state.signupCaseProposals);updateSignupGate()}
async function checkSignupKakaoStatus(){if(!state.signupRecipientId){state.signupKakaoRegistered=false;updateSignupGate();return false}try{var data=await req('/api/poc/master-press/signup/kakao-status?recipient_id='+encodeURIComponent(state.signupRecipientId)+'&_='+Date.now());state.signupKakaoRegistered=!!data.kakao_registered;if(!state.signupKakaoRegistered)state.signupRecipientId='';updateSignupGate();return state.signupKakaoRegistered}catch(error){state.signupKakaoRegistered=false;updateSignupGate();toast(error.message);return false}}
async function loadSignup(){try{await refreshAdminSessionSilent();renderSignup(await req('/api/poc/master-press/signup/bootstrap?_='+Date.now()));if(state.isAdmin){var proposals=await req('/api/poc/master-press/case-proposals?_='+Date.now());state.signupCaseProposals=proposals.items||[];renderCaseProposals(state.signupCaseProposals)}await checkSignupKakaoStatus()}catch(error){toast(error.message)}}
