function articleStatusLabel(item){var labels={pending:'공통 분석 대기',processing:'공통 분석 중',completed:'공통 분석 완료',failed:'공통 분석 실패'};return labels[item.status]||item.status||'수집됨'}
function caseStatusLabel(item){var delivery=item.deliveries||{};if(item.evaluation_status==='excluded')return '후보 제외';if(item.evaluation_status==='pending')return '유사도 판정 대기';if(item.evaluation_status==='processing')return '유사도 판정 중';if(item.evaluation_status==='failed')return '판정 실패';if(item.decision==='send'){if(delivery.sent)return '발송 완료';if(delivery.pending||delivery.retry)return '발송 예정';return '조건 충족'}return item.decision==='low'?'발송 제외':'판정 대기'}
function caseStatusReason(item){var parts=[],categories=userReasons(item.low_score_categories||[]),reasons=userReasons(item.reasons||[]),error=userReason(item.evaluation_error);if(item.evaluation_status==='excluded'){parts.push('후보 제외: '+(error||categories[0]||reasons[0]||'케이스 조건과 맞지 않아 LLM 판정 전에 제외했습니다.'))}else if(item.decision==='low'){parts.push('발송 제외: '+(reasons[0]||categories[0]||'케이스 발송 기준을 충족하지 못했습니다.'));if(item.evidence_status)parts.push('근거 상태: '+(evidenceLabel(item.evidence_status)||userReason(item.evidence_status)));var extra=categories.filter(function(value){return value!==reasons[0]});if(extra.length)parts.push('추가 사유: '+extra.slice(0,2).join(' / '))}else if(item.evaluation_status==='failed'){parts.push('판정 실패: '+(error||'오류 기록 없음'))}else if(item.evaluation_status==='pending'){parts.push('LLM 판정 대기 중입니다.')}else if(item.evaluation_status==='processing'){parts.push('LLM 판정 처리 중입니다.')}else if(item.decision==='send'){parts.push('발송 조건 충족');if(reasons.length)parts.push(reasons.slice(0,2).join(' / '))}return parts.join('\n')}
function llmScoreText(item){if(item.llm_status==='unavailable')return 'LLM 판정실패';if(item.evaluation_status==='failed')return 'LLM 판정실패';if(item.evaluation_status==='pending')return 'LLM 대기';if(item.evaluation_status==='processing')return 'LLM 처리중';if(item.evaluation_status!=='completed')return 'LLM 미완료';return 'LLM '+Number(item.llm_score||0).toFixed(1)+'%'}
function articleHasSentDelivery(item){return Number((item.case_summary||{}).sent||0)>0}
function similarGroupKey(item){return item&&item.similar_group_id&&Number(item.similar_group_size||0)>1?String(item.similar_group_id):String(item&&item.id||'')}
function similarBasisLabel(group){var status=group&&group.status,basis=group&&group.basis;if(status==='finalized')return basis==='semantic'?'의미 유사도 기준':'키워드+의미 유사도 기준';if(basis==='hybrid')return '의미 유사도 반영 중';return '키워드 임시 기준'}
function groupSimilarArticles(items){if(!state.articleGroupSimilar)return items.map(function(item){return{item:item,similar:[],basis:'',status:''}});var buckets={},order=[];(items||[]).forEach(function(item){var key=similarGroupKey(item);if(!buckets[key]){buckets[key]={items:[],basis:item.similar_group_basis||'',status:item.similar_group_status||'',score:Number(item.similar_group_score||0)};order.push(key)}buckets[key].items.push(item);if(item.similar_group_status==='finalized')buckets[key].status='finalized';if(item.similar_group_basis==='semantic'||item.similar_group_basis==='hybrid')buckets[key].basis=item.similar_group_basis;buckets[key].score=Math.max(buckets[key].score,Number(item.similar_group_score||0))});return order.map(function(key){var bucket=buckets[key],head=bucket.items[0],similar=bucket.items.slice(1).map(function(item){return{item:item,score:Number(item.similar_group_score||bucket.score||0),basis:item.similar_group_basis||bucket.basis,status:item.similar_group_status||bucket.status}});return{item:head,similar:similar,basis:bucket.basis,status:bucket.status,score:bucket.score}})}
