function similarArticleBundleHtml(similar,group){if(!similar||!similar.length)return'';var label=similarBasisLabel(group||{});return '<details class="similar-article-bundle"><summary>유사 기사 묶음 보기('+(similar.length+1)+'건)<span class="similar-basis">'+esc(label)+'</span></summary><div class="similar-article-list">'+similar.map(function(entry){var item=entry.item||{},score=Number(entry.score||0);return '<article><div><a href="'+esc(item.original_url)+'" target="_blank" rel="noopener noreferrer">'+esc(item.title)+'</a><small>'+esc(item.publisher||'언론사 미확인')+' · '+fmt(item.published_at||item.first_seen_at)+' · '+esc(similarBasisLabel(entry))+'</small></div><b>'+(score?score.toFixed(1)+'%':'-')+'</b></article>'}).join('')+'</div></details>'}
