  var needsCaseRun=cases.some(function(value){return value.llm_retry_needed||value.evaluation_status==='pending'||value.evaluation_status==='processing'||value.evaluation_status==='failed'});var articleAnalysisButton=state.isAdmin?'<button class="analysis-button article-reanalysis-button" type="button" data-reanalyze-article="'+esc(item.id)+'">'+(needsCaseRun?'분석':'재분석')+'</button>':'';
  var bundle=similarArticleBundleHtml(similar||[],group||{});
