$('syncPressReleases').onclick=async function(){var button=this;button.disabled=true;try{var result=await req('/api/poc/master-press/admin/press-releases/sync',{method:'POST',body:'{}'});toast('지금 동기화 완료 · 신규 '+Number(result.new||0)+'건');loadPress()}catch(error){toast(error.message)}finally{button.disabled=false}};

function renderDashboardWords(words,scopeLabel){var root=$('dashboardWordCloud'),meta=$('dashboardWordMeta');if(!root)return;if(!state.activeCase&&!state.activeOrganization){if(meta)meta.textContent='기관 또는 케이스를 선택하세요.';root.innerHTML='<div class="empty compact">기관 또는 케이스별 핵심 화두를 표시합니다.</div>';return}var visibleWords=(words||[]).slice(0,10);if(!visibleWords.length){if(meta)meta.textContent=(scopeLabel||'최근 7일')+' · 분석 결과 없음';root.innerHTML='<div class="empty compact">표시할 화두가 아직 없습니다.</div>';return}var max=Math.max.apply(null,visibleWords.map(function(item){return Number(item.value||0)}));if(meta)meta.textContent=(scopeLabel||'최근 7일')+' · 핵심 화두 10개';root.innerHTML=visibleWords.map(function(item,index){var ratio=Number(item.value||0)/max,rankWeight=Math.pow(1-index/9,.62),angle=index*2.3999632297,radius=index?26+Math.sqrt(index)*36*(1-ratio*.14):0,x=Math.max(15,Math.min(85,50+Math.cos(angle)*radius/3.45)),y=Math.max(14,Math.min(86,50+Math.sin(angle)*radius/3.15)),size=Math.round(13+23*rankWeight*(.8+.2*ratio));return '<span class="topic-word rank-'+index+'" style="left:'+x+'%;top:'+y+'%;font-size:'+size+'px">'+esc(item.label)+'</span>'}).join('')}
async function loadDashboardWords(){var params=new URLSearchParams({days:'7',delivery_only:'1'}),scopeLabel='';if(state.activeCase){params.set('case_id',state.activeCase);if(state.activeOrganization)params.set('organization_id',state.activeOrganization);scopeLabel='발송 대상 · 케이스 · 최근 7일'}else if(state.activeOrganization){params.set('organization_id',state.activeOrganization);params.set('scope','organization');scopeLabel='발송 대상 · 기관 전체 · 최근 7일'}else{renderDashboardWords([]);return}var requestedCase=state.activeCase,requestedOrganization=state.activeOrganization;try{var data=await req('/api/poc/master-press/analysis/insights?'+params.toString());if(requestedCase===state.activeCase&&requestedOrganization===state.activeOrganization)renderDashboardWords(data.words||[],scopeLabel)}catch(error){var meta=$('dashboardWordMeta');if(meta)meta.textContent='화두 집계 실패'}}

async function loadDashboard(caseId,organizationId){
  if(state.dashboardLoading){state.dashboardReloadRequested=true;return}
  state.dashboardLoading=true;state.activeCase=caseId||'';state.activeOrganization=organizationId||'';
  try{
    var adminSession=await fetch('/api/admin/session',{cache:'no-store',credentials:'same-origin'});state.isAdmin=adminSession.ok;
    var params=new URLSearchParams();if(state.activeOrganization)params.set('organization_id',state.activeOrganization);if(state.activeCase)params.set('case_id',state.activeCase);if(state.activeTags.length)params.set('tags',state.activeTags.join(','));if(state.articleSearch)params.set('q',state.articleSearch);params.set('_',String(Date.now()));
    renderDashboardSnapshot(await req('/api/poc/master-press/dashboard?'+params.toString()));
    loadDashboardWords();
  }catch(error){toast(error.message)}finally{state.dashboardLoading=false;if(state.dashboardReloadRequested){state.dashboardReloadRequested=false;loadDashboard(state.activeCase,state.activeOrganization)}}
}

function renderPipelineStats(stats,deliveries,deliveryErrors){
  var common=stats.article_jobs||{},embeddings=stats.embedding||{},cases=stats.case_jobs||{},providers=stats.providers||{};
  var commonProvider=providers.common||{},embeddingProvider=providers.embedding||{},caseProvider=providers.case||{},delivery={},deliveryErrors=deliveryErrors||{};
  (deliveries||[]).forEach(function(item){delivery[item.status]=Number(item.value||0)});
  function set(id,value){var node=document.getElementById(id);if(node)node.textContent=value}
  function waiting(stage){return Number(stage.pending||0)+Number(stage.processing||0)}
  function errorText(stage,fallback){var current=Number(stage.failed_current!=null?stage.failed_current:fallback||0),total=Number(stage.failed_total!=null?stage.failed_total:current);return current.toLocaleString()+"건 (누적: "+total.toLocaleString()+"건)"}
  function providerName(provider){return {groq:'Groq',openrouter:'OpenRouter',cloudflare:'Cloudflare',gemini:'Gemini',ollama:'Ollama'}[provider]||provider||'Provider'}
  function simpleModelName(model){var text=String(model||'').trim();if(!text)return '모델 미설정';var lower=text.toLowerCase();if(lower.indexOf('llama-3.1-8b')>=0)return 'Llama 3.1 8B';if(lower.indexOf('gemma-4-26b')>=0)return 'Gemma 4 26B';if(lower.indexOf('gemini')>=0&&lower.indexOf('flash')>=0)return 'Gemini Flash Lite';if(lower.indexOf('nomic-embed')>=0)return 'nomic-embed';if(lower.indexOf('gpt-oss-20b')>=0)return 'GPT OSS 20B';if(lower.indexOf('qwen')>=0)return text.split('/').pop().replace(/:free$/,'');return text.split('/').pop().replace(/^@cf\//,'').replace(/^google\//,'').replace(/:free$/,'').replace(/-/g,' ').slice(0,32)}
  function providerLabel(provider,platform){provider=provider||{};var status=provider.exhausted?'충전 대기':(provider.available?'사용 가능':(provider.connected===false?'연결 필요':'확인 중'));return providerName(provider.provider||platform)+' · '+simpleModelName(provider.model)+' · '+status}
  function chainLabel(chain,fallbackPlatform){chain=chain||[];var active=chain.find(function(item){return item&&item.available})||chain.find(function(item){return item&&!item.exhausted})||chain[0]||{};return providerLabel(active,fallbackPlatform)}
  set("commonPending",waiting(common).toLocaleString());set("commonCompleted",Number(common.completed||0).toLocaleString());set("commonFailed",errorText(common,Number(common.failed||0)));
  set("embeddingPending",waiting(embeddings).toLocaleString());set("embeddingCompleted",Number(embeddings.completed||0).toLocaleString());set("embeddingFailed",errorText(embeddings,Number(embeddings.failed||0)));
  set("casePending",waiting(cases).toLocaleString());set("caseCompleted",Number(cases.completed||0).toLocaleString());set("caseFailed",errorText(cases,Number(cases.failed||0)));
  set("deliveryPending",(Number(delivery.pending||0)+Number(delivery.retry||0)).toLocaleString());set("deliverySent",Number(delivery.sent||0).toLocaleString());set("pipelineFailed",errorText(deliveryErrors,Number(delivery.failed||0)+Number(delivery.retry||0)));
  set("pipelineAverage",Number(stats.average_seconds||0).toFixed(1)+"초");set("pipelineTotal",Number(stats.processed_articles||stats.total||0).toLocaleString()+"건");
  set("commonProviderMeta",commonProvider.chain?chainLabel(commonProvider.chain,"Cloudflare"):providerLabel(commonProvider,commonProvider.state_label||"Cloudflare"));set("embeddingProviderMeta",providerLabel(embeddingProvider,"Ollama"));set("caseProviderMeta",caseProvider.chain?chainLabel(caseProvider.chain,"OpenRouter"):providerLabel(caseProvider,"OpenRouter"));
  var operation=providers.operation||{},notice=$("operationNotice");
  if(notice){notice.hidden=!operation.halted;notice.textContent=operation.halted?String(operation.message||"영업중지-토큰이 다 떨어졌어요. 낼 00시에 뵈어요~"):""}
}

async function reanalyzeArticle(articleId){
  if(!articleId)return;
  if(!confirm('이 기사에 대한 모든 케이스 판정을 다시 대기 상태로 돌리고 최신 결과로 덮어쓸까요? 조건을 만족하면 카카오 발송까지 진행됩니다.'))return;
  try{
    var data=await req('/api/poc/master-press/admin/analysis/'+encodeURIComponent(articleId)+'/reanalyze',{method:'POST',body:'{}'});
    var counts=data.counts||{};
    toast('기사 재분석을 시작했습니다. '+Number(counts.queued||0)+'개 케이스가 판정 대기열에 들어갔습니다.');
    await loadDashboard(state.activeCase,state.activeOrganization);
    clearInterval(reanalyzeArticle.timer);
    var ticks=0;
    reanalyzeArticle.timer=setInterval(function(){
      ticks+=1;
      loadDashboard(state.activeCase,state.activeOrganization);
      if(ticks>=12)clearInterval(reanalyzeArticle.timer);
    },5000);
  }catch(error){toast(error.message)}
}

async function openAnalysis(articleId,caseId){try{var data=await req('/api/poc/master-press/admin/analysis/'+encodeURIComponent(articleId)+'/'+encodeURIComponent(caseId)+'/report');state.analysis={articleId:articleId,caseId:caseId,data:data};var report=data.current||{};var retry=data.reanalysis;var result=retry&&retry.result||{};var components=report.components||{};var evidence=components.evidence_status?evidenceLabel(components.evidence_status):'기록 없음';var status=retry?'<p><b>재분석 상태:</b> '+esc(retry.status)+(retry.error?' · '+esc(retry.error):'')+'</p>':'';$('analysisContent').innerHTML='<p><b>사용 모델:</b> '+esc(report.model||'기록 없음')+'</p><p><b>하이브리드 유사도:</b> 종합 '+Number(components.final_score||components.similarity_score||0).toFixed(1)+'% · 벡터 '+Number(components.semantic_score||0).toFixed(1)+'% · LLM '+Number(components.llm_raw_score!=null?components.llm_raw_score:(report.llm&&report.llm.score)||0).toFixed(1)+'% · '+esc(evidence)+(components.delivery_eligible===false?' · 발송 제외':'')+'</p><p><b>정규화된 어조:</b> '+esc((report.llm&&report.llm.tone)||'기록 없음')+((report.llm&&report.llm.tone_ambiguous)?' · 복수 응답을 단일값으로 정규화':'')+'</p><p><b>LLM 입력 기사 내용:</b> '+esc((report.input_content&&report.input_content.source)||'기존 기록')+' · 본문 '+Number((report.input_content&&report.input_content.body_length)||0).toLocaleString()+'자 · 요약문 '+Number((report.input_content&&report.input_content.snippet_length)||0).toLocaleString()+'자'+(report.reconstructed?' · 과거 기록을 현재 기사 데이터로 재구성':'')+'</p><h3>점수·근거 검증</h3><pre>'+esc(JSON.stringify({components:components,evidence_validation:report.evidence_validation||{},evidence_candidates:report.input_content&&report.input_content.evidence_candidates||{}},null,2))+'</pre>'+status+(retry&&retry.status==='completed'?'<h3>재분석 결과</h3><pre>'+esc(JSON.stringify(result.analysis_report||result,null,2))+'</pre>':'')+'<h3>시스템 프롬프트</h3><pre>'+esc(report.system_prompt||'기존 분석 기록에는 시스템 프롬프트가 없습니다.')+'</pre><h3>주제 검색 사용자 프롬프트 및 기사 입력</h3><pre>'+esc(report.user_prompt||report.prompt||'초기 분석 기록이 없습니다.')+'</pre><h3>LLM 답변</h3><pre>'+esc(report.raw_response||'초기 분석 기록이 없습니다.')+'</pre>';var models=(data.llm_models&&data.llm_models.length?data.llm_models:(state.caseLlmModels.length?state.caseLlmModels:[report.model,data.selected_llm_model]));$('reanalysisModel').innerHTML=models.filter(Boolean).map(function(model){return '<option value="'+esc(model)+'">'+esc(model)+'</option>'}).join('')||'<option value="">선택 가능한 OpenRouter 모델이 없습니다.</option>';$('reanalysisModel').value=report.model||data.selected_llm_model||models[0]||'';$('analysisDialog').showModal()}catch(error){toast(error.message)}}
function readyLabel(key){return {naver_news:'네이버 뉴스',kakao_login:'카카오 로그인',token_encryption:'토큰 암호화',supabase:'Supabase',groq:'Groq',ollama:'Ollama 임베딩',openrouter:'OpenRouter'}[key]||key}
