function caseKeywordSuggestionHtml(item){var data=item.sent_keyword_suggestions||{},keywords=data.keywords||[];var content=keywords.length?keywords.map(function(value){return esc(value.keyword)+' '+Number(value.count||0)+'건'}).join(' · '):'발송 표본 대기';return '<small class="case-keyword-suggestions">발송 기준 Top 5 · '+content+'</small>'}
