function maskPersonName(value){var text=String(value||'').trim();if(!text)return '구독자';var seen=false;return Array.from(text).map(function(ch){if(/\s/.test(ch))return ch;if(!seen){seen=true;return ch}return '*' }).join('')}
function adminMemberDisplayName(value){value=String(value||'구독자');return state.adminShowMemberNames?value:maskPersonName(value)}
function announcementIsLive(item){if(!item||!item.is_active)return false;var ends=String(item.ends_at||'');return !ends||new Date(ends).getTime()>=Date.now()}
function renderAdminSignupRequests(items){
  var root=$("adminSignupRequests");if(!root)return;
  var linked={},groups=[],byKey={};
  (items||[]).forEach(function(item){
    if(item.recipient_id)linked[item.recipient_id]=true;
    var key=item.recipient_id?"recipient:"+item.recipient_id:"request:"+item.id;
    if(!byKey[key]){
      byKey[key]={key:key,recipient_id:item.recipient_id||"",name:item.applicant_name||item.masked_name||"구독자",created_at:item.created_at,requests:[],requestOrganizations:{}};
      groups.push(byKey[key]);
    }
    byKey[key].name=byKey[key].name||item.applicant_name||item.masked_name||"구독자";
    byKey[key].created_at=byKey[key].created_at||item.created_at;
    var organizationKey=item.organization_id||item.id;
    if(!byKey[key].requestOrganizations[organizationKey]){byKey[key].requestOrganizations[organizationKey]=true;byKey[key].requests.push(item)}
  });
  var rows=groups.map(function(group){
    var requestedCount=0,approvedCount=0;
    group.requests.forEach(function(item){(item.case_requests||[]).forEach(function(caseItem){if(caseItem.status==="pending")requestedCount++;if(caseItem.status==="approved")approvedCount++})});
    var summaryText=requestedCount+" 케이스 승인요청, "+approvedCount+" 케이스 승인완료";
    var sections=group.requests.map(function(item){
      var requested={};(item.case_requests||[]).forEach(function(caseItem){requested[caseItem.case_id]=caseItem});
      var available=state.cases.filter(function(caseItem){return caseItem.organization_id===item.organization_id&&caseItem.is_active});
      var cases=available.map(function(caseItem){var current=requested[caseItem.id]||{},status=current.status||"none",checked=status==="pending"||status==="approved";return "<label class=\"admin-member-case\"><input type=\"checkbox\" data-member-request=\""+esc(item.id)+"\" data-member-case=\""+esc(caseItem.id)+"\" "+(checked?"checked":"")+"><span>"+esc(caseItem.name)+"</span><small>"+esc(status==="none"?"미신청":signupCaseStatusLabel(status))+"</small></label>"}).join("")||"<div class=\"empty compact\">활성 케이스가 없습니다.</div>";
      var statusText=esc(item.organization_name||"부처 미확인")+" · "+esc(signupStatusLabel(item.status))+(item.kakao_registered?" · 카카오 등록완료":" · 카카오 등록대기");
      return "<section class=\"admin-member-subscription\"><div class=\"admin-member-meta\"><small>"+statusText+"</small><time>"+fmt(item.created_at)+"</time></div><div class=\"admin-member-cases\">"+cases+"</div><div class=\"row-actions member-actions\"><button data-subscription-apply=\""+esc(item.id)+"\">적용</button></div>"+(item.admin_note?"<small class=\"admin-note\">"+esc(item.admin_note)+"</small>":"")+"</section>";
    }).join("");
    var actions=group.recipient_id?"<div class=\"row-actions member-actions member-main-actions\"><button data-test=\""+esc(group.recipient_id)+"\">테스트</button><button data-remove-recipient=\""+esc(group.recipient_id)+"\">해제(관리자 권한)</button></div>":"<div class=\"row-actions member-actions member-main-actions\"><button data-delete-signup-request=\""+esc(group.requests[0]&&group.requests[0].id||"")+"\">신청 기록 삭제</button></div>";
    return "<details class=\"admin-signup-row member-row compact-member-row\"><summary class=\"admin-member-summary\"><b>"+esc(adminMemberDisplayName(group.name))+"</b><small>"+esc(summaryText)+"</small></summary><div class=\"admin-member-body\">"+actions+sections+"</div></details>";
  });
  var extras=state.recipients.filter(function(item){return !linked[item.id]}).map(function(item){var connected=item.connection_status==="connected",temporary=["구독 신청자","카카오 수신자",""] .indexOf(String(item.label||""))>=0,name=temporary?"신청 미완료":adminMemberDisplayName(item.label),kind=temporary?"카카오 동의 후 구독 요청 미완료":"수동 등록";return '<details class="admin-signup-row member-row compact-member-row manual-member '+(temporary?'temporary-member':'')+'"><summary class="admin-member-summary"><b>'+esc(name)+'</b><small>'+esc(kind)+'</small></summary><div class="admin-member-body"><small class="recipient-connection '+(connected?'connected':'failed')+'">'+esc(kind)+' · '+esc(item.connection_label||(connected?'연결 성공':'연결 실패'))+' · '+fmt(item.created_at)+'</small><div class="row-actions member-actions"><button data-test="'+esc(item.id)+'">테스트</button><button data-remove-recipient="'+esc(item.id)+'">해제(관리자 권한)</button></div></div></details>'});
  root.innerHTML=rows.concat(extras).join("")||"<div class=\"empty compact\">구독 요청이 없습니다.</div>";
}
function renderAnnouncements(items){
  var root=$('announcementList');if(!root)return;items=items||[];
  var tab=state.announcementTab||'active',visible=tab==='active'?items.filter(announcementIsLive):items;
  document.querySelectorAll('[data-announcement-tab]').forEach(function(button){button.classList.toggle('active',button.dataset.announcementTab===tab);button.setAttribute('aria-selected',button.dataset.announcementTab===tab?'true':'false');button.onclick=function(){state.announcementTab=button.dataset.announcementTab||'active';renderAnnouncements(items)}});
  root.innerHTML=visible.length?visible.map(function(item){var live=announcementIsLive(item);return '<div class="announcement-row '+(live?'':'off')+'"><div><b>'+esc(item.title||'공지')+'</b><small>'+esc(item.body||'')+'</small><time>'+(live?'게시중':'종료/내림')+' · 종료 '+(item.ends_at?fmt(item.ends_at):'기한 없음')+'</time></div><div class="announcement-actions">'+(live?'<button data-delete-announcement="'+esc(item.id)+'">내리기</button>':'')+'<button class="danger" data-purge-announcement="'+esc(item.id)+'">삭제</button></div></div>'}).join(''):'<div class="empty compact">'+(tab==='active'?'게시중인 공지가 없습니다.':'등록된 공지가 없습니다.')+'</div>';
  root.querySelectorAll('[data-delete-announcement]').forEach(function(button){button.onclick=async function(){if(!confirm('이 공지를 팝업에서 내릴까요? 목록에는 보관됩니다.'))return;try{var data=await req('/api/poc/master-press/admin/announcements/'+encodeURIComponent(button.dataset.deleteAnnouncement),{method:'DELETE'});renderAnnouncements(data.items||[]);toast('공지사항을 내렸습니다.')}catch(error){toast(error.message)}}});
  root.querySelectorAll('[data-purge-announcement]').forEach(function(button){button.onclick=async function(){if(!confirm('이 공지를 완전히 삭제할까요?'))return;try{var data=await req('/api/poc/master-press/admin/announcements/'+encodeURIComponent(button.dataset.purgeAnnouncement)+'?hard=1',{method:'DELETE'});renderAnnouncements(data.items||[]);toast('공지사항을 삭제했습니다.')}catch(error){toast(error.message)}}});
}


