function adminStatusText(status,defaultLimit){status=status||{};var limit=Number(status.soft_limit||defaultLimit||0),used=Number(status.attempts||0),period=status.period==='rolling 24h'?'최근 24시간':(status.period==='UTC day'?'UTC일':'오늘'),base=(status.connected?'연결 성공':'연결 실패');if(status.error)base+=' · '+status.error;base+=' · '+period+' '+used.toLocaleString()+'/'+limit.toLocaleString()+'회';if(Number(status.token_soft_limit||0))base+=' · '+Number(status.tokens||0).toLocaleString()+'/'+Number(status.token_soft_limit||0).toLocaleString()+'토큰';if(status.reset_at)base+=' · 다음 초기화 '+fmt(status.reset_at);else if(status.reset_label)base+=' · 초기화 '+status.reset_label;return base}
