async function loadAdminModelStatuses(){var run=(state.adminModelStatusRun||0)+1;state.adminModelStatusRun=run;var targets=['common','case','reserve1','reserve2','embedding'];targets.forEach(function(target){var el=$(adminModelStatusTarget(target));if(el)el.textContent=(el.textContent||'저장값 표시')+' · 확인 대기'});for(var i=0;i<targets.length;i++){var target=targets[i],el=$(adminModelStatusTarget(target));if(state.adminModelStatusRun!==run)return;if(el)el.textContent=(el.textContent||'저장값 표시').replace(/ · 확인 대기$/,'')+' · 상세 확인 중';try{var data=await req('/api/poc/master-press/admin/model-status?target='+encodeURIComponent(target));if(state.adminModelStatusRun!==run)return;applyAdminModelStatus(target,data)}catch(error){if(state.adminModelStatusRun!==run)return;var statusEl=$(adminModelStatusTarget(target));if(statusEl)statusEl.textContent='상세 확인 실패 · '+error.message}}}

