function sortableDropTarget(container,y){var rows=Array.from(container.querySelectorAll('[data-sort-case]:not(.dragging)'));return rows.reduce(function(closest,row){var box=row.getBoundingClientRect(),offset=y-box.top-box.height/2;if(offset<0&&offset>closest.offset)return{offset:offset,element:row};return closest},{offset:-Infinity,element:null}).element}
