function bindCaseOrderRows(){document.querySelectorAll('.sortable-case-list').forEach(function(list){var original='';list.querySelectorAll('[data-sort-case]').forEach(function(row){row.addEventListener('dragstart',function(event){original=Array.from(list.querySelectorAll('[data-sort-case]')).map(function(item){return item.dataset.sortCase}).join(',');row.classList.add('dragging');event.dataTransfer.effectAllowed='move';event.dataTransfer.setData('text/plain',row.dataset.sortCase)});row.addEventListener('dragend',function(){row.classList.remove('dragging')})});list.addEventListener('dragover',function(event){event.preventDefault();var dragging=list.querySelector('.dragging');if(!dragging)return;var after=sortableDropTarget(list,event.clientY);if(after==null)list.appendChild(dragging);else list.insertBefore(dragging,after)});list.addEventListener('drop',function(event){event.preventDefault();var ordered=Array.from(list.querySelectorAll('[data-sort-case]')).map(function(row,index){var no=row.querySelector('.case-order-no');if(no)no.textContent=index+1;return row.dataset.sortCase});if(ordered.join(',')!==original)saveCaseOrder(list.dataset.organizationId,ordered)})})}
