$('reanalyzeButton').onclick=async function(){if(!state.analysis)return;var model=$('reanalysisModel').value;if(!model){toast('재분석 모델을 선택하세요.');return}try{var result=await req('/api/poc/master-press/admin/analysis/'+encodeURIComponent(state.analysis.articleId)+'/'+encodeURIComponent(state.analysis.caseId)+'/reanalyze',{method:'POST',body:JSON.stringify({model:model})});toast('재분석을 대기열에 넣었습니다. 현재 분석 기사 다음에 실행합니다.');var jobId=result.job.id;var timer=setInterval(async function(){try{var report=await req('/api/poc/master-press/admin/analysis/'+encodeURIComponent(state.analysis.articleId)+'/'+encodeURIComponent(state.analysis.caseId)+'/report');var job=report.reanalysis;if(job&&job.id===jobId&&job.status==='completed'){clearInterval(timer);if(confirm('재분석 결과가 나왔습니다. 이번 분석 결과를 반영할까요?')){var applied=await req('/api/poc/master-press/admin/analysis/'+encodeURIComponent(jobId)+'/apply',{method:'POST',body:'{}'});$('analysisDialog').close();loadDashboard(state.activeCase,state.activeOrganization);if(applied.send_eligible&&confirm('추가 알림으로 유사도가 확인되었습니다. 발송하시겠습니까?')){await req('/api/poc/master-press/admin/analysis/'+encodeURIComponent(jobId)+'/send',{method:'POST',body:'{}'});toast('재분석 결과를 반영하고 카카오톡 발송을 요청했습니다.')}else toast('재분석 결과를 반영했습니다.')}else toast('재분석 결과를 반영하지 않았습니다.')}}catch(error){clearInterval(timer);toast(error.message)}},5000)}catch(error){toast(error.message)}};
