function sentKeywordSuggestionPanel(data){data=data||{};var keywords=data.keywords||[];return '<div class="sent-keyword-improvement"><h3>발송 기준 Top 5 키워드</h3><div class="score-parts">'+(keywords.map(function(item){return '<span>'+esc(item.keyword)+' '+Number(item.count||0)+'건 · '+Number(item.coverage_pct||0).toFixed(1)+'%</span>'}).join('')||'<span>발송 표본 대기</span>')+'</div><small>최근 '+Number(data.days||30)+'일 실제 발송 기사 '+Number(data.sent_articles||0)+'건 기준 · 기존 포함/필수 키워드는 제외</small></div>'}
async function loadImprovement(){var id=$('improvementCase').value;if(!id){$('improvementContent').innerHTML='<div class="empty">케이스를 먼저 만드세요.</div>';return}try{var data=await req('/api/poc/master-press/admin/cases/'+id+'/improvements?days=7');var categories=Object.entries(data.categories||{}).sort(function(a,b){return b[1]-a[1]});$('improvementContent').innerHTML='<div class="improvement-score"><span>7일 저점 표본</span><b>'+(data.sample_count||0)+'</b><small>평균 '+Number(data.average_score||0).toFixed(1)+'%</small></div>'+sentKeywordSuggestionPanel(data.sent_keyword_suggestions)+'<div><h3>주요 원인</h3><div class="score-parts">'+(categories.map(function(pair){return '<span>'+esc(userReason(pair[0]))+' '+pair[1]+'</span>'}).join('')||'<span>분석 대기</span>')+'</div><h3>설정 개선 제안</h3><ul>'+((data.suggestions||[]).map(function(item){return '<li>'+esc(item)+'</li>'}).join('')||'<li>데이터가 쌓이면 사례별 제안을 표시합니다.</li>')+'</ul></div>'}catch(error){toast(error.message)}}
$('improvementCase').onchange=loadImprovement;
function renderRefreshCountdown(){var label=$('refreshCountdown');if(!label)return;if(!state.refreshSeconds){label.textContent='(다음 갱신: 안함)';return}var minute=Math.floor(state.refreshRemaining/60);var second=state.refreshRemaining%60;label.textContent='(다음 갱신: '+String(minute).padStart(2,'0')+':'+String(second).padStart(2,'0')+'초)'}
function startAutoRefresh(){clearInterval(state.countdownTimer);state.refreshSeconds=Number($('refreshInterval').value);state.refreshRemaining=state.refreshSeconds;renderRefreshCountdown();if(!state.refreshSeconds)return;state.countdownTimer=setInterval(function(){if($('dashboardView').hidden)return;state.refreshRemaining-=1;if(state.refreshRemaining<=0){state.refreshRemaining=state.refreshSeconds;loadDashboard(state.activeCase,state.activeOrganization)}renderRefreshCountdown()},1000)}
$('refreshInterval').onchange=startAutoRefresh;
